}

// =============================================================================
// app_icons.dart — Centralized icon registry using Phosphor Icons
// =============================================================================

import 'package:flutter/material.dart';
import 'package:phosphor_flutter/phosphor_flutter.dart';
import '../../features/diagnostics/domain/enums/test_status.dart';

/// Mapping from app semantic icon to Phosphor icon data.
enum AppIcon {
  // Status
  pass(PhosphorIcons.checkCircle, PhosphorIconsRegular.checkCircle),
  fail(PhosphorIcons.xCircle, PhosphorIconsRegular.xCircle),
  warning(PhosphorIcons.warning, PhosphorIconsRegular.warning),
  error(PhosphorIcons.warningCircle, PhosphorIconsRegular.warningCircle),
  skipped(PhosphorIcons.minusCircle, PhosphorIconsRegular.minusCircle),
  info(PhosphorIcons.info, PhosphorIconsRegular.info),

  // Navigation
  dashboard(PhosphorIcons.squaresFour, PhosphorIconsRegular.squaresFour),
  diagnostics(PhosphorIcons.activity, PhosphorIconsRegular.activity),
  config(PhosphorIcons.sliders, PhosphorIconsRegular.sliders),
  report(PhosphorIcons.fileText, PhosphorIconsRegular.fileText),
  settings(PhosphorIcons.gear, PhosphorIconsRegular.gear),

  // Test groups
  systemAdapters(PhosphorIcons.cpu, PhosphorIconsRegular.cpu),
  connectivity(PhosphorIcons.shareNetwork, PhosphorIconsRegular.shareNetwork),
  internet(PhosphorIcons.globe, PhosphorIconsRegular.globe),
  remoteHost(PhosphorIcons.cloud, PhosphorIconsRegular.cloud),
  website(PhosphorIcons.browser, PhosphorIconsRegular.browser),

  // Actions
  play(PhosphorIcons.play, PhosphorIconsRegular.play),
  stop(PhosphorIcons.stop, PhosphorIconsRegular.stop),
  refresh(PhosphorIcons.arrowsClockwise, PhosphorIconsRegular.arrowsClockwise),
  close(PhosphorIcons.x, PhosphorIconsRegular.x),
  target(PhosphorIcons.crosshair, PhosphorIconsRegular.crosshair),
  timer(PhosphorIcons.timer, PhosphorIconsRegular.timer),

  // Platforms
  apple(PhosphorIcons.appleLogo, PhosphorIconsRegular.appleLogo),
  android(PhosphorIcons.androidLogo, PhosphorIconsRegular.androidLogo),
  windows(PhosphorIcons.windowsLogo, PhosphorIconsRegular.windowsLogo),
  linux(PhosphorIcons.linuxLogo, PhosphorIconsRegular.linuxLogo),
  desktop(PhosphorIcons.desktop, PhosphorIconsRegular.desktop),
  phone(PhosphorIcons.deviceMobile, PhosphorIconsRegular.deviceMobile),
  tablet(PhosphorIcons.deviceTablet, PhosphorIconsRegular.deviceTablet),
  laptop(PhosphorIcons.laptop, PhosphorIconsRegular.laptop),

  // Misc
  copy(PhosphorIcons.copy, PhosphorIconsRegular.copy),
  share(PhosphorIcons.share, PhosphorIconsRegular.share),
  language(PhosphorIcons.translate, PhosphorIconsRegular.translate),
  email(PhosphorIcons.envelope, PhosphorIconsRegular.envelope),
  speed(PhosphorIcons.gauge, PhosphorIconsRegular.gauge),
  wifi(PhosphorIcons.wifiHigh, PhosphorIconsRegular.wifiHigh),
  cellular(PhosphorIcons.cellSignalHigh, PhosphorIconsRegular.cellSignalHigh),
  network(PhosphorIcons.network, PhosphorIconsRegular.network),
  lock(PhosphorIcons.lock, PhosphorIconsRegular.lock),
  unlock(PhosphorIcons.lockOpen, PhosphorIconsRegular.lockOpen),
  ;

  final IconData fill;
  final IconData regular;
  const AppIcon(this.fill, this.regular);

  /// Build a Flutter [Icon] widget with the given size and color.
  Widget icon({double? size, Color? color, bool useFill = false}) {
    return Icon(useFill ? fill : regular, size: size, color: color);
  }
}

/// Extension to get the appropriate icon for a [TestStatus].
extension TestStatusIcon on TestStatus {
  AppIcon get appIcon {
    switch (this) {
      case TestStatus.pass:    return AppIcon.pass;
      case TestStatus.fail:    return AppIcon.fail;
      case TestStatus.warning: return AppIcon.warning;
      case TestStatus.error:   return AppIcon.error;
      case TestStatus.skipped: return AppIcon.skipped;
      case TestStatus.info:    return AppIcon.info;
    }
  }
}

