/// Reusable summary card widget showing pass/warn/fail/skip counts.
///
/// Uses [dashboardStatsProvider] to get the latest counts from the
/// diagnostic run state.  When no run has completed, shows zeros.
class SummaryCards extends ConsumerWidget {
  const SummaryCards({super.key});

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final stats = ref.watch(dashboardStatsProvider);

    final pass = stats['pass'] ?? 0;
    final fail = stats['fail'] ?? 0;
    final warn = stats['warn'] ?? 0;
    final skip = stats['skip'] ?? 0;
    final total = stats['completed'] ?? (pass + fail + warn + skip);

    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      mainAxisSize: MainAxisSize.min,
      children: [
        // Label with total
        Padding(
          padding: const EdgeInsets.only(bottom: 8),
          child: Row(children: [
            Expanded(
                child: Text(
              'Summary',
              style: TextStyle(
                  color: AppTheme.textSecondary,
                  fontSize: 11,
                  fontWeight: FontWeight.w600,
                  letterSpacing: 0.6),
            )),
            Text('Total: $total',
                style: TextStyle(color: AppTheme.textSecondary, fontSize: 10)),
          ]),
        ),

        // Cards in a 2x2 grid
        Row(
          children: [
            Expanded(
              child: _SummaryCard(
                count: pass,
                label: 'Pass',
                color: AppTheme.passGreen,
                icon: Icons.check_circle,
              ),
            ),
            const SizedBox(width: 6),
            Expanded(
              child: _SummaryCard(
                count: warn,
                label: 'Warning',
                color: AppTheme.warnYellow,
                icon: Icons.warning_amber,
              ),
            ),
          ],
        ),
        const SizedBox(height: 6),
        Row(
          children: [
            Expanded(
              child: _SummaryCard(
                count: fail,
                label: 'Fail',
                color: AppTheme.failRed,
                icon: Icons.cancel,
              ),
            ),
            const SizedBox(width: 6),
            Expanded(
              child: _SummaryCard(
                count: skip,
                label: 'Skipped',
                color: AppTheme.skipGray,
                icon: Icons.remove_circle_outline,
              ),
            ),
          ],
        ),
      ],
    );
  }
}

/// A single summary card showing one count with a colored icon and label.
class _SummaryCard extends StatelessWidget {
  final int count;
  final String label;
  final Color color;
  final IconData icon;

  const _SummaryCard({
    required this.count,
    required this.label,
    required this.color,
    required this.icon,
  });

  @override
  Widget build(BuildContext context) {
    return Container(
      padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 10),
      decoration: BoxDecoration(
        color: color.withValues(alpha: 0.08),
        borderRadius: BorderRadius.circular(8),
        border: Border.all(
          color: color.withValues(alpha: 0.25),
          width: 1,
        ),
      ),
      child: Row(
        children: [
          Icon(icon, size: 20, color: color),
          const SizedBox(width: 8),
          Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            mainAxisSize: MainAxisSize.min,
            children: [
              Text(
                '$count',
                style: TextStyle(
                  color: color,
                  fontSize: 20,
                  fontWeight: FontWeight.w700,
                  height: 1.0,
                ),
              ),
              const SizedBox(height: 1),
              Text(
                label,
                style: TextStyle(
                  color: AppTheme.textSecondary.withValues(alpha: 0.8),
                  fontSize: 9,
                  fontWeight: FontWeight.w500,
                ),
              ),
            ],
          ),
        ],
      ),
    );
  }
}

